def get_db():
    conn = sqlite3.connect('app.db')
    conn.row_factory = sqlite3.Row
    return conn

def generate_cache_key(prefix, *args, **kwargs):
    key_data = f"{prefix}:{args}:{sorted(kwargs.items())}"
    return hashlib.md5(key_data.encode()).hexdigest()

def cache_result(prefix, ttl=300):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = generate_cache_key(prefix, *args, **kwargs)
            
            cached_data = memcache_client.get(cache_key)
            if cached_data is not None:
                return cached_data
            
            result = func(*args, **kwargs)
            
            memcache_client.set(cache_key, result, expire=ttl)
            
            return result
        return wrapper
    return decorator

def invalidate_cache(prefix, *args, **kwargs):
    cache_key = generate_cache_key(prefix, *args, **kwargs)
    memcache_client.delete(cache_key)

def invalidate_pattern(pattern):
    pass

@cache_result('db_users', ttl=600)
def get_all_users():
    conn = get_db()
    cursor = conn.cursor()
    cursor.execute('SELECT id, name, email, created_at FROM users')
    users = [dict(row) for row in cursor.fetchall()]
    conn.close()
    return users

@cache_result('db_user_by_id', ttl=600)
def get_user_by_id(user_id):
    conn = get_db()
    cursor = conn.cursor()
    cursor.execute('SELECT id, name, email, created_at FROM users WHERE id = ?', (user_id,))
    row = cursor.fetchone()
    conn.close()
    return dict(row) if row else None

