@app.route('/users/<int:user_id>', methods=['GET'])
def user_detail(user_id):
    user_data = get_user_by_id(user_id)
    if user_data:
        return jsonify(user_data)
    return jsonify({'error': 'User not found'}), 404

@app.route('/users', methods=['POST'])
def create_user():
    data = request.get_json()
    name = data.get('name')
    email = data.get('email')
    
    if not name or not email:
        return jsonify({'error': 'Name and email are required'}), 400
    
    conn = get_db()
    cursor = conn.cursor()
    cursor.execute('INSERT INTO users (name, email) VALUES (?, ?)', (name, email))
    user_id = cursor.lastrowid
    conn.commit()
    conn.close()
    
    invalidate_cache('db_users')
    
    return jsonify({
        'id': user_id,
        'name': name,
        'email': email
    }), 201

@app.route('/products', methods=['GET'])
def products():
    category = request.args.get('category')
    
    if category:
        products_data = get_products_by_category(category)
    else:
        products_data = get_all_products()
    
    return jsonify({
        'products': products_data,
        'count': len(products_data)
    })

@app.route('/products', methods=['POST'])
def create_product():
    data = request.get_json()
    name = data.get('name')
    price = data.get('price')
    category = data.get('category')
    
    if not name or price is None or not category:
        return jsonify({'error': 'Name, price, and category are required'}), 400
    
    conn = get_db()
    cursor = conn.cursor()
    cursor.execute('INSERT INTO products (name, price, category) VALUES (?, ?, ?)', 
                   (name, price, category))
    product_id = cursor.lastrowid
    conn.commit()
    conn.close()
    
    invalidate_cache('db_products')
    invalidate_cache('db_products_by_category', category)
    
    return jsonify({
        'id': product_id,
        'name': name,
        'price': price,
        'category': category
    }), 201

